85	/****************************************************************************/
86	/* FPGA metadata types                                                      */
87	/****************************************************************************/
88	/* t_metadata_value, and t_metadata_dict provide a types to store
89	 * metadata about the FPGA architecture and routing routing graph along side
90	 * the pb_type, grid, node and edge descriptions.
91	 *
92	 * The metadata is stored as a simple key/value map.  key's are string and an
93	 * optional coordinate. t_metadata_value provides the value storage, which is a
94	 * string.
95	 */
96	
97	// Metadata value storage.
98	class t_metadata_value {
99	  public:
100	    explicit t_metadata_value(vtr::interned_string v) noexcept
101	        : value_(v) {}
102	    explicit t_metadata_value(const t_metadata_value& o) noexcept
103	        : value_(o.value_) {}
104	
105	    // Return string value.
106	    vtr::interned_string as_string() const { return value_; }
107	
108	    t_metadata_value& operator=(const t_metadata_value& o) noexcept {
109	        if (this != &o) {
110	            value_ = o.value_;
111	        }
112	        return *this;
113	    }
114	
115	  private:
116	    vtr::interned_string value_;
117	};
118	
119	// Metadata storage dictionary.
120	struct t_metadata_dict : vtr::flat_map<
121	                             vtr::interned_string,
122	                             std::vector<t_metadata_value>,
123	                             vtr::interned_string_less> {
124	    // Is this key present in the map?
125	    inline bool has(vtr::interned_string key) const {
126	        return this->count(key) >= 1;
127	    }
128	
129	    // Get all metadata values matching key.
130	    //
131	    // Returns nullptr if key is not found.
132	    inline const std::vector<t_metadata_value>* get(vtr::interned_string key) const {
133	        auto iter = this->find(key);
134	        if (iter != this->end()) {
135	            return &iter->second;
136	        }
137	        return nullptr;
138	    }
139	
140	    // Get metadata values matching key.
141	    //
142	    // Returns nullptr if key is not found or if multiple values are present
143	    // per key.
144	    inline const t_metadata_value* one(vtr::interned_string key) const {
145	        auto values = get(key);
146	        if (values == nullptr) {
147	            return nullptr;
148	        }
149	        if (values->size() != 1) {
150	            return nullptr;
151	        }
152	        return &((*values)[0]);
153	    }
154	
155	    // Adds value to key.
156	    void add(vtr::interned_string key, vtr::interned_string value) {
157	        // Get the iterator to the key, which may already have elements if
158	        // add was called with this key in the past.
159	        (*this)[key].emplace_back(value);
160	    }
161	};
