477	/* Describes the type for a physical tile
478	 * name: unique identifier for type
479	 * num_pins: Number of pins for the block
480	 * capacity: Number of blocks of this type that can occupy one grid tile (typically used by IOs).
481	 * width: Width of large block in grid tiles
482	 * height: Height of large block in grid tiles
483	 *
484	 * pinloc: Is set to true if a given pin exists on a certain position of a
485	 *         block. Derived from pin_location_distribution/pin_loc_assignments
486	 *
487	 * pin_layer_offset/pin_width_offset/pin_height_offset: offset from the anchor point
488	 * of the block type in the x,y, and layer (dice number) direction.
489	 *
490	 * pin_location_distribution: The pin distribution type
491	 * num_pin_loc_assignments: The number of strings within each pin_loc_assignments
492	 * pin_loc_assignments: The strings for a custom pin location distribution.
493	 *                      Valid only for pin_location_distribution == E_CUSTOM_PIN_DISTR
494	 *
495	 * num_class: Number of logically-equivalent pin classes
496	 * class_inf: Information of each logically-equivalent class
497	 *
498	 * pin_avg_width_offset: Average width offset to specified pin (exact if only a single physical pin instance)
499	 * pin_avg_height_offset: Average height offset to specified pin (exact if only a single physical pin instance)
500	 * pin_class: The class a pin belongs to
501	 * is_ignored_pin: Whether or not a pin is ignored during rr_graph generation and routing.
502	 *                 This is usually the case for clock pins and other global pins unless the
503	 *                 clock_modeling option is set to route the clock through regular inter-block
504	 *                 wiring or through a dedicated clock network.
505	 * is_pin_global: Whether or not this pin is marked as global. Clock pins and other specified
506	 *                global pins in the architecture file are marked as global.
507	 *
508	 * fc_specs: The Fc specifications for all pins
509	 *
510	 * switchblock_locations: Switch block configuration for this block.
511	 *                        Each element describes the type of SB which should be
512	 *                        constructed at the specified location.
513	 *                        Note that the SB is located to the top-right of the
514	 *                        grid tile location. [0..width-1][0..height-1]
515	 *
516	 * area: Describes how much area this logic block takes, if undefined, use default
517	 * type_timing_inf: timing information unique to this type
518	 * num_drivers: Total number of output drivers supplied
519	 * num_receivers: Total number of input receivers supplied
520	 * index: Keep track of type in array for easy access
521	 * logical_tile_index: index of the corresponding logical block type
522	 *
523	 * In general, the physical tile is a placeable physical resource on the FPGA device,
524	 * and it is allowed to contain a heterogeneous set of logical blocks (pb_types).
525	 *
526	 * Each physical tile must specify at least one sub tile, that is a physical location
527	 * on the sub tiles stacks. This means that a physical tile occupies an (x, y) location on the grid,
528	 * and it has at least one sub tile slot that allows for a placement within the (x, y) location.
529	 *
530	 * Therefore, to identify the location of a logical block within the device grid, we need to
531	 * specify four different coordinates:
532	 *      - x         : horizontal coordinate
533	 *      - y         : vertical coordinate
534	 *      - sub tile  : location within the sub tile stack at an (x, y) physical location
535	 *      -layer_num  : the layer that block is located at. In case of a single die, layer_num is 0.
536	 *
537	 * A physical tile is heterogeneous as it allows the placement of different kinds of logical blocks within,
538	 * that can share the same (x, y) placement location.
539	 *
540	 */
541	struct t_physical_tile_type {
542	    std::string name;
543	    int num_pins = 0;
544	    int num_inst_pins = 0;
545	    int num_input_pins = 0;
546	    int num_output_pins = 0;
547	    int num_clock_pins = 0;
548	
549	    std::vector<int> clock_pin_indices;
550	
551	    int capacity = 0;
552	
553	    int width = 0;
554	    int height = 0;
555	
556	    vtr::NdMatrix<std::vector<bool>, 3> pinloc; /* [0..width-1][0..height-1][0..3][0..num_pins-1] */
557	
558	    std::vector<t_class> class_inf; /* [0..num_class-1] */
559	
560	    // Primitive class is referred to a classes that are in the primitive blocks. These classes are
561	    // used during flat-routing to route the nets.
562	    // The starting number of primitive classes
563	    int primitive_class_starting_idx = -1;
564	    std::unordered_map<int, t_class> primitive_class_inf; // [primitive_class_num] -> primitive_class_inf
565	
566	    std::vector<int> pin_width_offset;                // [0..num_pins-1]
567	    std::vector<int> pin_height_offset;               // [0..num_pins-1]
568	    std::vector<int> pin_class;                       // [0..num_pins-1]
569	    std::unordered_map<int, int> primitive_pin_class; // [primitive_pin_num] -> primitive_class_num
570	    std::vector<bool> is_ignored_pin;                 // [0..num_pins-1]
