634	/* Holds the capacity range of a certain sub_tile block within the parent physical tile type.
635	 * E.g. TILE_X has the following sub tiles:
636	 *          - SUB_TILE_A: capacity_range --> 0 to 4
637	 *          - SUB_TILE_B: capacity_range --> 5 to 11
638	 *          - SUB_TILE_C: capacity_range --> 12 to 16
639	 *
640	 * Total TILE_X capacity is 17
641	 */
642	struct t_capacity_range {
643	    int low = 0;
644	    int high = 0;
645	
646	    void set(int low_cap, int high_cap) {
647	        low = low_cap;
648	        high = high_cap;
649	    }
650	
651	    bool is_in_range(int cap) const {
652	        return cap >= low and cap <= high;
653	    }
654	
655	    int total() const {
656	        return high - low + 1;
657	    }
