660	/**
661	 * @brief Describes the possible placeable blocks within a physical tile type.
662	 *
663	 * Heterogeneous blocks:
664	 *
665	 * The sub tile allows to have heterogeneous blocks placed at the same grid location.
666	 * Heterogeneous blocks are blocks which do not share either the same functionality or the
667	 * IO interface, but do share the same (x, y) grid location.
668	 * For each heterogeneous block type than, there should be a corresponding sub tile to enable
669	 * its placement within the physical tile.
670	 *
671	 * For further information there is a tutorial on the VTR documentation page.
672	 *
673	 *
674	 * Equivalent sites:
675	 *
676	 * Moreover, the same sub tile enables to allow the placement of different implementations
677	 * of a logical block.
678	 * This means that two blocks that have different internal functionalities, but the IO interface of one block
679	 * is a subset of the other, they can be placed at the same sub tile location within the physical tile.
680	 * These two blocks can be identified as equivalent, hence they can belong to the same sub tile.
681	 */
682	struct t_sub_tile {
683	    std::string name;
684	
685	    // Mapping between the subtile's pins and the physical pins corresponding
686	    // to the physical tile type.
687	    std::vector<int> sub_tile_to_tile_pin_indices;
688	
689	    std::vector<t_physical_tile_port> ports;
690	
691	    std::vector<t_logical_block_type_ptr> equivalent_sites; ///>List of netlist blocks (t_logical_block) that one could
692	                                                            ///>place within this sub tile.
693	
694	    t_capacity_range capacity; ///>Indicates the total number of sub tile instances of this type placeable at a
695	                               ///>physical location.
696	                               ///>E.g.: capacity can range from 4 to 7, meaning that there are four placeable sub tiles
697	                               ///>      at a physical location, and compatible netlist blocks can be placed at sub_tile
698	                               ///>      indices ranging from 4 to 7.
699	    t_class_range class_range; // Range of the root-level classes
700	
701	    std::vector<std::unordered_map<t_logical_block_type_ptr, t_class_range>> primitive_class_range; // [rel_cap][logical_block_ptr] -> class_range
702	    std::vector<std::unordered_map<t_logical_block_type_ptr, t_pin_range>> intra_pin_range;         // [rel_cap][logical_block_ptr] -> intra_pin_range
703	
704	    int num_phy_pins = 0;
705	
706	    int index = -1;
707	
708	  public:
709	    int total_num_internal_pins() const;
710	
711	    /**
712	     * @brief Returns the physical tile port given the port name and the corresponding sub tile
713	     */
714	    const t_physical_tile_port* get_port(std::string_view port_name);
715	
716	    /**
717	     * @brief Returns the physical tile port given the pin name and the corresponding sub tile
718	     */
719	    const t_physical_tile_port* get_port_by_pin(int pin) const;
