762	/**
763	 * @brief Describes The location of a physical tile
764	 * @param x The x location of the physical tile on the given die
765	 * @param y The y location of the physical tile on the given die
766	 * @param layer_num The die number of the physical tile. If the FPGA only has one die, or the physical tile is located
767	 *                  on the base die, layer_num is equal to zero. If the physical tile is location on the die immediately
768	 *                  above the base die, the layer_num is 1 and so on.
769	 */
770	struct t_physical_tile_loc {
771	    int x = ARCH_FPGA_UNDEFINED_VAL;
772	    int y = ARCH_FPGA_UNDEFINED_VAL;
773	    int layer_num = ARCH_FPGA_UNDEFINED_VAL;
774	
775	    t_physical_tile_loc() = default;
776	
777	    t_physical_tile_loc(int x_val, int y_val, int layer_num_val)
778	        : x(x_val)
779	        , y(y_val)
780	        , layer_num(layer_num_val) {}
781	
782	    // Returns true if this type location layer_num/x/y is not equal to ARCH_FPGA_UNDEFINED_VAL
783	    operator bool() const {
784	        return !(x == ARCH_FPGA_UNDEFINED_VAL || y == ARCH_FPGA_UNDEFINED_VAL || layer_num == ARCH_FPGA_UNDEFINED_VAL);
785	    }
786	
787	    /**
788	     * @brief Comparison operator for t_physical_tile_loc
789	     *
790	     * Tiles are ordered first by layer number, then by x, and finally by y.
791	     */
792	    friend bool operator<(const t_physical_tile_loc& lhs, const t_physical_tile_loc& rhs) {
793	        if (lhs.layer_num != rhs.layer_num)
794	            return lhs.layer_num < rhs.layer_num;
795	        if (lhs.x != rhs.x)
796	            return lhs.x < rhs.x;
797	        return lhs.y < rhs.y;
798	    }
799	
800	    friend bool operator==(const t_physical_tile_loc& a, const t_physical_tile_loc& b) {
801	        return a.x == b.x && a.y == b.y && a.layer_num == b.layer_num;
802	    }
803	
804	    friend bool operator!=(const t_physical_tile_loc& a, const t_physical_tile_loc& b) {
805	        return !(a == b);
806	    }
807	};
