809	namespace std {
810	template<>
811	struct hash<t_physical_tile_loc> {
812	    std::size_t operator()(const t_physical_tile_loc& v) const noexcept {
813	        std::size_t seed = std::hash<int>{}(v.x);
814	        vtr::hash_combine(seed, v.y);
815	        vtr::hash_combine(seed, v.layer_num);
816	        return seed;
817	    }
818	};
