923	/*************************************************************************************************
924	 * PB Type Hierarchy                                                                             *
925	 *************************************************************************************************
926	 *
927	 * VPR represents the 'type' of block types corresponding to FPGA grid locations using a hierarchy
928	 * of t_pb_type objects.
929	 *
930	 * The root t_pb_type corresponds to a single top level block type and maps to a particular type
931	 * of location in the FPGA device grid (e.g. Logic, DSP, RAM etc.).
932	 *
933	 * A non-root t_pb_type represents an intermediate level of hierarchy within the root block type.
934	 *
935	 * The PB Type hierarchy corresponds to the tags specified in the FPGA architecture description:
936	 *
937	 *      struct              XML Tag
938	 *      ------              ------------
939	 *      t_pb_type           <pb_type/>
940	 *      t_mode              <mode/>
941	 *      t_interconnect      <interconnect/>
942	 *      t_port              <port/>
943	 *
944	 * The various structures hold pointers to each other which encode the hierarchy.
945	 */
946	
947	/** Describes the type of clustered block if a root (parent_mode == nullptr), an
948	 *  intermediate level of hierarchy (parent_mode != nullptr), or a leaf/primitive
949	 *  (num_modes == 0, model != nullptr).
950	 *
951	 *  This (along with t_mode) corresponds to the hierarchical specification of
952	 *  block modes that users provide in the architecture (i.e. <pb_type/> tags).
953	 *
954	 *  It is also useful to note that a single t_pb_type may represent multiple instances of that
955	 *  type in the architecture (see the num_pb field).
956	 *
957	 *  In VPR there is a single instance of a t_pb_type for each type, which is referenced as a
958	 *  flyweight by other objects (e.g. t_pb_graph_node).
959	 *
960	 *  Data members:
961	 *      name: name of the physical block type
962	 *      num_pb: maximum number of instances of this physical block type sharing one parent
963	 *      blif_model: the string in the blif circuit that corresponds with this pb type
964	 *      class_type: Special library name
965	 *      modes: Different modes accepted
966	 *      ports: I/O and clock ports
967	 *      num_clock_pins: A count of the total number of clock pins
968	 *      num_input_pins: A count of the total number of input pins
969	 *      num_output_pins: A count of the total number of output pins
970	 *      num_pins: A count of the total number of pins
971	 *      timing: Timing matrix of block [0..num_inputs-1][0..num_outputs-1]
972	 *      parent_mode: mode of the parent block
973	 *      t_mode_power: ???
974	 *      meta: Table storing extra arbitrary metadata attributes.
975	 */
976	struct t_pb_type {
977	    char* name = nullptr;
978	    int num_pb = 0;
979	    char* blif_model = nullptr;
980	    LogicalModelId model_id;
981	    e_pb_type_class class_type = UNKNOWN_CLASS;
982	
983	    t_mode* modes = nullptr; /* [0..num_modes-1] */
984	    int num_modes = 0;
985	    t_port* ports = nullptr; /* [0..num_ports] */
986	    int num_ports = 0;
987	
988	    int num_clock_pins = 0;
989	    int num_input_pins = 0; /* inputs not including clock pins */
990	    int num_output_pins = 0;
991	
992	    int num_pins = 0;
993	
994	    t_mode* parent_mode = nullptr;
995	    int depth = 0; /* depth of pb_type */
996	
997	    std::vector<t_pin_to_pin_annotation> annotations;
998	
999	    int index_in_logical_block = 0; /* assign a unique id to each pb_type in a logical block */
1000	
1001	    /* Power related members */
1002	    t_pb_type_power* pb_type_power = nullptr;
1003	
1004	    t_metadata_dict meta;
1005	
1006	    /**
1007	     * @brief Check if t_pb_type is the root of the pb graph. Root pb_types correspond to a single top level block type and map to a particular type
1008	     * of location in the FPGA device grid (e.g. Logic, DSP, RAM etc.)
1009	     *
1010	     * @return if t_pb_type is root or not
1011	     */
1012	    inline bool is_root() const {
1013	        return parent_mode == nullptr;
1014	    }
1015	
1016	    /**
1017	     * @brief Check if t_pb_type is a primitive block or equivalently a leaf of the pb graph.
1018	     *
1019	     * @return if t_pb_type is primitive/leaf or not
1020	     */
1021	    inline bool is_primitive() const {
1022	        return num_modes == 0;
1023	    }
1024	
1025	    int get_max_primitives() const;
1026	    int get_max_depth() const;
1027	    int get_max_nets() const;
1028	};
