1251	/*************************************************************************************************
1252	 * PB Graph                                                                                      *
1253	 *************************************************************************************************
1254	 *
1255	 * The PB graph represents the flattened and elaborated connectivity within a t_pb_type (i.e.
1256	 * the routing resource graph), derived from the t_pb_type hierarchy.
1257	 *
1258	 * The PB graph is built of t_pb_graph_node and t_pb_graph_pin objects.
1259	 *
1260	 * There is a single PB graph associated with each root t_pb_type, and it is referenced in other objects (e.g.
1261	 * t_pb) as a flyweight.
1262	 *
1263	 */
1264	
1265	/** Describes the internal connectivity corresponding to a t_pb_type and t_mode of a cluster.
1266	 *
1267	 *  There is a t_pb_graph_node for each instance of the pb_type (i.e. t_pb_type may describe
1268	 *  num_pb instances of the type, with each instance represented as a t_pb_graph_node).
1269	 *  The distinction between the pb_type and the pb_graph_node is necessary since the 'position'
1270	 *  of a particular instance in the cluster is important when routing the cluster (since the routing
1271	 *  accessible from each position may be different).
1272	 *
1273	 *  Data members:
1274	 *      pb_type               : Pointer to the type of pb graph node this belongs to
1275	 *      placement_index       : there are a certain number of pbs available, this gives the index of the node
1276	 *      child_pb_graph_nodes  : array of children pb graph nodes organized into modes
1277	 *      parent_pb_graph_node  : parent pb graph node
1278	 *      total_primitive_count : Total number of this primitive type in the cluster. If there are 10 ALMs per cluster
1279	 *                              and 2 FFs per ALM (given the mode of the parent of this primitive) then the total is 20.
1280	 *                              This member is only used by nodes corresponding to primitive sites.
1281	 *      illegal_modes         : vector containing illegal modes that result in conflicts during routing
1282	 */
1283	class t_pb_graph_node {
1284	  public:
1285	    t_pb_type* pb_type;
1286	
1287	    int placement_index;
1288	
1289	    /*
1290	     * There is a root-level pb_graph_node assigned to each logical type. Each logical type can contain multiple primitives.
1291	     * If this pb_graph_node is associated with a primitive, a unique number is assigned to it within the logical block level.
1292	     */
1293	    int primitive_num = ARCH_FPGA_UNDEFINED_VAL;
1294	
1295	    /* Contains a collection of mode indices that cannot be used as they produce conflicts during VPR packing stage
1296	     *
1297	     * Illegal modes do arise when children of a graph_node do have inconsistent `edge_modes` with respect to
1298	     * the parent_pb.
1299	     * Example: Edges that connect LUTs A, B and C to the parent pb_graph_node refer to the correct parent's mode which is set to "LUTs",
1300	     *          but edges of LUT D have the mode of edge corresponding to a wrong parent's pb_graph_node mode, namely "LUTRAM".
1301	     *          This situation is unfeasible as the edge modes are inconsistent between siblings of the same parent pb_graph_node.
1302	     *          In this case, the "LUTs" mode of the parent pb_graph_node cannot be used as the LUT D is not able to have a feasible
1303	     *          edge mode that does relate with the other sibling's edge modes.
1304	     *
1305	     *          The "LUTs" index mode is added to the illegal_modes vector. The conflicting mode marked as illegal is the most restrictive one.
1306	     *          This means that LUT D is unable to be routed if using the parent's "LUTs" mode (otherwise "LUTs" mode would be selected for LUT D
1307	     *          as well), but LUTs A, B and C could still be routed using the parent pb_graph_node's mode "LUTRAM".
1308	     *          Therefore, "LUTs" is marked as illegal and all the LUTs (A, B, C and D) will have a consistent parent pb_graph_node mode, namely "LUTRAM".
1309	     *
1310	     * Usage: cluster_router uses this information to exclude the expansion of a node which has a not consistent mode.
1311	     *        Every time the mode consistency check fails, the index of the mode that causes the conflict is added to this vector.
1312	     * */
1313	    std::vector<int> illegal_modes;
1314	
1315	    t_pin_range pin_num_range;
1316	
1317	    t_pb_graph_pin** input_pins;  /* [0..num_input_ports-1] [0..num_port_pins-1]*/
1318	    t_pb_graph_pin** output_pins; /* [0..num_output_ports-1] [0..num_port_pins-1]*/
1319	    t_pb_graph_pin** clock_pins;  /* [0..num_clock_ports-1] [0..num_port_pins-1]*/
1320	
1321	    int num_input_ports;
1322	    int num_output_ports;
1323	    int num_clock_ports;
1324	
1325	    int* num_input_pins;  /* [0..num_input_ports - 1] */
1326	    int* num_output_pins; /* [0..num_output_ports - 1] */
1327	    int* num_clock_pins;  /* [0..num_clock_ports - 1] */
1328	
1329	    t_pb_graph_node*** child_pb_graph_nodes; /* [0..num_modes-1][0..num_pb_type_in_mode-1][0..num_pb-1] */
1330	    t_pb_graph_node* parent_pb_graph_node;
1331	
1332	    int total_pb_pins; /* only valid for top-level */
1333	
1334	    std::vector<size_t> input_pin_class_sizes;  /* Stores the number of pins in each input pin class indexed by input pin class number */
1335	    std::vector<size_t> output_pin_class_sizes; /* Stores the number of pins in each output pin class indexed by output pin class number */
1336	
1337	    int total_primitive_count; /* total number of this primitive type in the cluster */
1338	
1339	    /* Interconnect instances for this pb
1340	     * Only used for power
1341	     */
1342	    t_pb_graph_node_power* pb_node_power;
1343	    t_interconnect_pins** interconnect_pins; /* [0..num_modes-1][0..num_interconnect_in_mode] */
1344	
1345	    // Returns true if this pb_graph_node represents a primitive type (primitives have 0 modes)
1346	    bool is_primitive() const { return this->pb_type->is_primitive(); }
1347	
1348	    // Returns true if this pb_graph_node represents a root graph node (ex. clb)
1349	    bool is_root() const { return this->parent_pb_graph_node == nullptr; }
1350	
1351	    //Returns the number of pins on this graph node
1352	    //  Note this is the total for all ports on this node excluding any children (i.e. sum of all num_input_pins, num_output_pins, num_clock_pins)
1353	    int num_pins() const;
1354	    // Returns a string containing the hierarchical type name of the pb_graph_node
1355	    // Ex: clb[0][default]/lab[0][default]/fle[3][n1_lut6]/ble6[0][default]/lut6[0]
1356	    std::string hierarchical_type_name() const;
1357	};
